export default Layout;

import React, { useEffect, useRef, useState } from 'react';

const WebGPUCanvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const initWebGPU = async () => {
      if (!navigator.gpu) {
        setError("WebGPU is not supported in your browser.");
        return;
      }

      const adapter = await navigator.gpu.requestAdapter();
      if (!adapter) {
        setError("No appropriate GPUAdapter found.");
        return;
      }

      const device = await adapter.requestDevice();
      if (!canvasRef.current) return;

      const context = canvasRef.current.getContext('webgpu');
      if (!context) {
        setError("Could not get WebGPU context.");
        return;
      }

      const format = navigator.gpu.getPreferredCanvasFormat();
      context.configure({
        device,
        format,
        alphaMode: 'premultiplied',
      });

      // Simple Clear Loop (Placeholder for real WebGPU Animation)
      const render = () => {
        const commandEncoder = device.createCommandEncoder();
        const textureView = context.getCurrentTexture().createView();

        const renderPassDescriptor: GPURenderPassDescriptor = {
          colorAttachments: [
            {
              view: textureView,
              clearValue: { r: 0.02, g: 0.02, b: 0.03, a: 1.0 },
              loadOp: 'clear',
              storeOp: 'store',
            },
          ],
        };

        const passEncoder = commandEncoder.beginRenderPass(renderPassDescriptor);
        // INSERT SHADER LOGIC HERE
        passEncoder.end();

        device.queue.submit([commandEncoder.finish()]);
        requestAnimationFrame(render);
      };

      requestAnimationFrame(render);
    };

    initWebGPU();
  }, []);

  if (error) {
    return (
      <div className="w-full h-full flex items-center justify-center bg-zinc-900 border border-white/10 rounded-lg p-8 text-center">
        <div className="max-w-md">
          <p className="text-red-400 font-mono mb-2">GPU_INITIALIZATION_ERROR</p>
          <p className="text-gray-400 text-sm">{error}</p>
          <p className="mt-4 text-xs text-gray-500">Falling back to static background...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-full rounded-2xl overflow-hidden border border-white/5 shadow-2xl">
      <canvas ref={canvasRef} className="w-full h-full block" />
      <div className="absolute top-4 left-4 bg-black/50 backdrop-blur px-3 py-1 rounded text-[10px] mono text-blue-400 border border-blue-500/30">
        WEBGPU_ACTIVE
      </div>
    </div>
  );
};

export default WebGPUCanvas;

import React, { useState } from 'react';
import { Photo } from '../types';

const MOCK_PHOTOS: Photo[] = Array.from({ length: 12 }).map((_, i) => ({
