import React, { useState } from 'react';
import { ResearchPaper } from '../types';
import { GoogleGenAI } from '@google/genai';

const PAPERS: ResearchPaper[] = [
  {
    id: '1',
    title: 'Efficient WebGPU Parallelism for Fluid Simulations',
    authors: ['Me', 'Dr. J. Doe'],
    abstract: 'This paper discusses the implementation of complex Navier-Stokes equations using the new WebGPU standard...',
    date: '2024-05-12',
    tags: ['WebGPU', 'Physics', 'Computing'],
  },
  {
    id: '2',
    title: 'Neural Radiance Fields in Real-time Web Environments',
    authors: ['Me'],
    abstract: 'Investigating the performance bottlenecks of NeRF rendering on modern browser hardware...',
    date: '2023-11-04',
    tags: ['AI', 'Graphics', 'Web'],
  }
];

const ResearchSection: React.FC = () => {
  const [summary, setSummary] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState<string | null>(null);

  const summarizePaper = async (paper: ResearchPaper) => {
    setLoading(paper.id);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Summarize this research paper abstract in two clear sentences for a general audience: ${paper.abstract}`,
      });

      setSummary(prev => ({ ...prev, [paper.id]: response.text || "No summary available." }));
    } catch (err) {
      console.error(err);
      setSummary(prev => ({ ...prev, [paper.id]: "AI summarizing failed. Check API key." }));
    } finally {
      setLoading(null);
    }
  };

  return (
    <div className="px-6 lg:px-20 py-12 max-w-5xl mx-auto">
      <div className="mb-12">
        <h2 className="text-4xl font-bold tracking-tight mb-4">Publications & Research</h2>
        <p className="text-gray-400">Deep dives into computational graphics and distributed systems.</p>
      </div>

      <div className="space-y-8">
        {PAPERS.map((paper) => (
          <div key={paper.id} className="glass p-8 rounded-2xl border border-white/10 hover:border-blue-500/30 transition-all">
            <div className="flex flex-wrap gap-2 mb-4">
              {paper.tags.map(tag => (
                <span key={tag} className="text-[10px] mono bg-white/5 border border-white/10 px-2 py-1 rounded text-gray-400 uppercase tracking-tighter">
                  {tag}
                </span>
              ))}
            </div>
            <h3 className="text-2xl font-bold mb-2 group-hover:text-blue-400">{paper.title}</h3>
            <p className="text-sm text-blue-500 font-medium mb-4">{paper.authors.join(', ')} • {paper.date}</p>
            <p className="text-gray-400 leading-relaxed mb-6 italic">"{paper.abstract}"</p>

            <div className="flex flex-col sm:flex-row sm:items-center gap-4 pt-6 border-t border-white/5">
              <button 
                onClick={() => summarizePaper(paper)}
                disabled={loading === paper.id}
                className="px-6 py-2 bg-blue-600/20 text-blue-400 border border-blue-600/30 rounded-lg text-sm font-semibold hover:bg-blue-600/30 transition-all disabled:opacity-50"
              >
                {loading === paper.id ? 'Thinking...' : 'Summarize with Gemini AI'}
              </button>
              <button className="px-6 py-2 glass rounded-lg text-sm font-semibold hover:bg-white/10">
                Download PDF
              </button>
            </div>

            {summary[paper.id] && (
              <div className="mt-6 p-4 bg-white/5 rounded-lg border-l-2 border-blue-500 text-sm text-gray-300">
                <span className="block font-bold text-[10px] text-blue-400 uppercase mb-1">AI Summary</span>
                {summary[paper.id]}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default ResearchSection;

