import React, { useEffect, useRef, useState } from 'react';

const SHADER_CODE = `
struct Uniforms {
  time: f32,
  width: f32,
  height: f32,
  padding: f32,
};

@group(0) @binding(0) var<uniform> ui: Uniforms;

struct VertexOutput {
  @builtin(position) position: vec4<f32>,
  @location(0) uv: vec2<f32>,
};

@vertex
fn vs_main(@builtin(vertex_index) vertexIndex: u32) -> VertexOutput {
  var pos = array<vec2<f32>, 6>(
    vec2<f32>(-1.0, -1.0), vec2<f32>(1.0, -1.0), vec2<f32>(-1.0, 1.0),
    vec2<f32>(-1.0, 1.0), vec2<f32>(1.0, -1.0), vec2<f32>(1.0, 1.0)
  );

  var output: VertexOutput;
  output.position = vec4<f32>(pos[vertexIndex], 0.0, 1.0);
  output.uv = pos[vertexIndex];
  return output;
}

@fragment
fn fs_main(input: VertexOutput) -> @location(0) vec4<f32> {
  let aspect = ui.width / ui.height;
  var uv = input.uv;
  uv.x *= aspect;

  // Jumping logic
  let jump_height = 0.4;
  let jump_speed = 3.5;
  let y_offset = sin(ui.time * jump_speed) * jump_height;

  let center = vec2<f32>(0.0, y_offset);
  let dist = distance(uv, center);

  let radius = 0.25;
  let smoothness = 0.005;

  // Create smooth circle
  let circle = 1.0 - smoothstep(radius - smoothness, radius + smoothness, dist);

  // Colors
  let bubble_color = vec3<f32>(0.6, 0.6, 0.6);
  let bg_color = vec3<f32>(0.02, 0.02, 0.03);

  let final_color = mix(bg_color, bubble_color, circle);

  return vec4<f32>(final_color, 1.0);
}
`;

const WebGPUCanvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const initWebGPU = async () => {
      if (!(navigator as any).gpu) {
        setError("WebGPU is not supported in your browser.");
        return;
      }

      const adapter = await (navigator as any).gpu.requestAdapter();
      if (!adapter) {
        setError("No appropriate GPUAdapter found.");
        return;
      }

      const device = await adapter.requestDevice();
      if (!canvasRef.current) return;

      const context = canvasRef.current.getContext('webgpu') as any;
      if (!context) {
        setError("Could not get WebGPU context.");
        return;
      }

      const presentationFormat = (navigator as any).gpu.getPreferredCanvasFormat();
      context.configure({
        device,
        format: presentationFormat,
        alphaMode: 'premultiplied',
      });

      const shaderModule = device.createShaderModule({
        code: SHADER_CODE,
      });

      const pipeline = device.createRenderPipeline({
        layout: 'auto',
        vertex: {
          module: shaderModule,
          entryPoint: 'vs_main',
        },
        fragment: {
          module: shaderModule,
          entryPoint: 'fs_main',
          targets: [{ format: presentationFormat }],
        },
        primitive: {
          topology: 'triangle-list',
        },
      });

      // Uniform buffer for time and resolution
      const uniformBufferSize = 16; // 4 floats (time, width, height, padding)
      const uniformBuffer = device.createBuffer({
        size: uniformBufferSize,
        usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST,
      });

      const bindGroup = device.createBindGroup({
        layout: pipeline.getBindGroupLayout(0),
        entries: [
          {
            binding: 0,
            resource: { buffer: uniformBuffer },
          },
        ],
      });

      const render = (time: number) => {
        if (!canvasRef.current) return;

        // Resize handling
        const rect = canvasRef.current.getBoundingClientRect();
        canvasRef.current.width = rect.width * window.devicePixelRatio;
        canvasRef.current.height = rect.height * window.devicePixelRatio;

        // Update uniforms
        const uniformData = new Float32Array([
          time / 1000, 
          canvasRef.current.width, 
          canvasRef.current.height, 
          0
        ]);
        device.queue.writeBuffer(uniformBuffer, 0, uniformData);

        const commandEncoder = device.createCommandEncoder();
        const textureView = context.getCurrentTexture().createView();

        const renderPassDescriptor: any = {
          colorAttachments: [
            {
              view: textureView,
              clearValue: { r: 0.02, g: 0.02, b: 0.03, a: 1.0 },
              loadOp: 'clear',
              storeOp: 'store',
            },
          ],
        };

        const passEncoder = commandEncoder.beginRenderPass(renderPassDescriptor);
        passEncoder.setPipeline(pipeline);
        passEncoder.setBindGroup(0, bindGroup);
        passEncoder.draw(6);
        passEncoder.end();

        device.queue.submit([commandEncoder.finish()]);
        requestAnimationFrame(render);
      };

      requestAnimationFrame(render);
    };

    initWebGPU();
  }, []);

  if (error) {
    return (
      <div className="w-full h-full flex items-center justify-center bg-zinc-900 border border-white/10 rounded-lg p-8 text-center">
        <div className="max-w-md">
          <p className="text-red-400 font-mono mb-2">GPU_INITIALIZATION_ERROR</p>
          <p className="text-gray-400 text-sm">{error}</p>
          <p className="mt-4 text-xs text-gray-500">Falling back to static background...</p>
        </div>
      </div>
    );
  }

  return (
