    let angle = atan2(p.y, p.x);
    var w = sin(angle * 3.0 + t * 2.5) * 0.02;
    w += sin(angle * 5.0 - t * 4.0) * 0.012;
    w += sin(angle * 2.0 + t * 1.5) * 0.015;
