const SHADER_CODE = `
struct Uniforms {
  time: f32,
  width: f32,
  height: f32,
  padding: f32,
};

@group(0) @binding(0) var<uniform> ui: Uniforms;

struct VertexOutput {
  @builtin(position) position: vec4<f32>,
  @location(0) uv: vec2<f32>,
};

@vertex
fn vs_main(@builtin(vertex_index) vertexIndex: u32) -> VertexOutput {
  var pos = array<vec2<f32>, 6>(
    vec2<f32>(-1.0, -1.0), vec2<f32>(1.0, -1.0), vec2<f32>(-1.0, 1.0),
    vec2<f32>(-1.0, 1.0), vec2<f32>(1.0, -1.0), vec2<f32>(1.0, 1.0)
  );

  var output: VertexOutput;
  output.position = vec4<f32>(pos[vertexIndex], 0.0, 1.0);
  output.uv = pos[vertexIndex];
  return output;
}

fn get_environment(dir: vec3<f32>) -> vec3<f32> {
    let horizon = smoothstep(-0.2, 0.2, dir.y);
    let sky = mix(vec3<f32>(0.1, 0.15, 0.25), vec3<f32>(0.7, 0.85, 1.0), pow(max(0.0, dir.y), 1.2));
    let ground = mix(vec3<f32>(0.02, 0.02, 0.03), vec3<f32>(0.1, 0.1, 0.12), horizon);
    return mix(ground, sky, horizon);
}

fn get_wobble(p: vec2<f32>, t: f32) -> f32 {
    let angle = atan2(p.y, p.x);
    let dist = length(p);

    var w = sin(angle * 2.0 + t * 0.8) * 0.012;
    w += sin(angle * 3.0 - t * 1.2) * 0.008;

    return w * smoothstep(0.0, 0.1, dist);
}

@fragment
fn fs_main(input: VertexOutput) -> @location(0) vec4<f32> {
  let aspect = ui.width / ui.height;
  var uv = input.uv;
  uv.x *= aspect;

  let jump_speed = 1.4;
  let t = ui.time * jump_speed;

  let sin_val = abs(sin(t));
  let bounce = pow(sin_val, 0.7); 

  let velocity = cos(t);
  let stretch_factor = 0.1 * abs(velocity) * sin_val; 
  let impact_squash = 0.12 * pow(1.0 - sin_val, 4.0);

  let stretch = 1.0 + stretch_factor - impact_squash;
  let squash = 1.0 / stretch;

  let jump_height = 0.45;
  let y_offset = (bounce * jump_height) - 0.22;
  let center = vec2<f32>(0.0, y_offset);

  var p_local = (uv - center);
  let dist_to_center = length(p_local);

  // RADIATING RAYS CALCULATION
  let angle = atan2(p_local.y, p_local.x);
  var rays = sin(angle * 8.0 + ui.time * 0.4) * 0.5 + 0.5;
  rays *= sin(angle * 3.0 - ui.time * 0.2) * 0.5 + 0.5;
  let ray_intensity = pow(rays, 3.0) * 0.12 * smoothstep(1.5, 0.0, dist_to_center);

  // AMBIENT GLOW
  let ambient_glow = 0.08 * smoothstep(0.8, 0.0, dist_to_center);
  let glow_color = vec3<f32>(0.3, 0.45, 0.7) * (ray_intensity + ambient_glow);

  p_local.y /= stretch;
  p_local.x /= squash;

  let dist_raw = length(p_local);
  let base_radius = 0.35;

  let wobble = get_wobble(p_local, ui.time);
  let deformed_radius = base_radius + wobble;

  // Set background to a dark mix with the radiating glow
  var final_color = vec3<f32>(0.02, 0.02, 0.025) + glow_color;

  if (dist_raw < deformed_radius) {
    let p_norm = p_local / deformed_radius;
    let z_base = sqrt(max(0.0, 1.0 - dot(p_norm, p_norm)));

    let eps = 0.015;
    let w_current = get_wobble(p_local, ui.time);
    let wobble_dx = (get_wobble(p_local + vec2<f32>(eps, 0.0), ui.time) - w_current) / eps;
    let wobble_dy = (get_wobble(p_local + vec2<f32>(0.0, eps), ui.time) - w_current) / eps;

    var normal = normalize(vec3<f32>(p_norm.x + wobble_dx * 0.05, p_norm.y + wobble_dy * 0.05, z_base));

    let view = vec3<f32>(0.0, 0.0, 1.0);
    let reflect_dir = reflect(-view, normal);

    let env_reflection = get_environment(reflect_dir);

    let fresnel = pow(1.0 - max(0.0, dot(normal, view)), 3.0);
    let diffuse = max(0.0, dot(normal, normalize(vec3<f32>(0.5, 1.0, 0.5))));

    let bubble_base = vec3<f32>(0.5, 0.55, 0.6) * diffuse * 0.25;

    let irid_freq = 3.0;
    let irid = vec3<f32>(
        0.5 + 0.4 * cos(fresnel * irid_freq + ui.time * 0.5),
        0.5 + 0.4 * cos(fresnel * irid_freq + 2.0 + ui.time * 0.5),
        0.5 + 0.4 * cos(fresnel * irid_freq + 4.0 + ui.time * 0.5)
    );

    let light_dir = normalize(vec3<f32>(0.3, 0.5, 1.0));
    let half_vec = normalize(view + light_dir);

    let specular = pow(max(0.0, dot(normal, half_vec)), 12.0);

    let bubble_color = mix(bubble_base, env_reflection, 0.65 + fresnel * 0.35) 
                     + (specular * 0.4) 
                     + (irid * fresnel * 0.1);

    let edge_mask = smoothstep(deformed_radius, deformed_radius - 0.008, dist_raw);
    final_color = mix(final_color, bubble_color, edge_mask);
  }

  return vec4<f32>(final_color, 1.0);
}
`;

