    let diffuse = max(0.0, dot(normal, normalize(vec3<f32>(0.5, 1.0, 0.5))));

    let submarine_blue = vec3<f32>(0.0, 0.35, 0.55);
    let bubble_base = submarine_blue * (diffuse * 0.3 + 0.4); 

