  }

  return vec4<f32>(final_color, 1.0);
}
`;

const WebGPUCanvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let animationId: number;
    let isMounted = true;

    const initWebGPU = async () => {
      const gpu = (navigator as any).gpu;
      if (!gpu) {
        setError("WebGPU is not supported in your browser.");
        return;
      }

      const adapter = await gpu.requestAdapter();
      if (!adapter) {
        setError("No appropriate GPUAdapter found.");
        return;
      }

      const device = await adapter.requestDevice();
      if (!canvasRef.current || !isMounted) return;

      const context = canvasRef.current.getContext('webgpu') as any;
      if (!context) {
        setError("Could not get WebGPU context.");
        return;
      }

      const presentationFormat = gpu.getPreferredCanvasFormat();
      context.configure({
        device,
        format: presentationFormat,
        alphaMode: 'premultiplied',
      });

      const shaderModule = device.createShaderModule({ code: SHADER_CODE });

      const pipeline = device.createRenderPipeline({
        layout: 'auto',
        vertex: {
          module: shaderModule,
          entryPoint: 'vs_main',
        },
        fragment: {
          module: shaderModule,
          entryPoint: 'fs_main',
          targets: [{ format: presentationFormat }],
        },
        primitive: { topology: 'triangle-list' },
      });

      const uniformBuffer = device.createBuffer({
        size: 16,
        usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST,
      });

      const bindGroup = device.createBindGroup({
        layout: pipeline.getBindGroupLayout(0),
        entries: [{ binding: 0, resource: { buffer: uniformBuffer } }],
      });

      const render = (time: number) => {
        if (!canvasRef.current || !isMounted) return;

        const rect = canvasRef.current.getBoundingClientRect();
        const dpr = window.devicePixelRatio || 1;

        // 只有当尺寸大于0时才进行渲染配置，防止生产环境初始化时的尺寸波动
        if (rect.width > 0 && rect.height > 0) {
            const targetWidth = rect.width * dpr;
            const targetHeight = rect.height * dpr;

            if (canvasRef.current.width !== targetWidth || canvasRef.current.height !== targetHeight) {
                canvasRef.current.width = targetWidth;
                canvasRef.current.height = targetHeight;
            }

            const uniformData = new Float32Array([
              time / 1000, 
              canvasRef.current.width, 
              canvasRef.current.height, 
              0
            ]);
            device.queue.writeBuffer(uniformBuffer, 0, uniformData);

            const commandEncoder = device.createCommandEncoder();
            const textureView = context.getCurrentTexture().createView();

            const passEncoder = commandEncoder.beginRenderPass({
              colorAttachments: [{
                view: textureView,
                clearValue: { r: 0.01, g: 0.01, b: 0.012, a: 1.0 },
                loadOp: 'clear',
                storeOp: 'store',
              }],
            });

            passEncoder.setPipeline(pipeline);
            passEncoder.setBindGroup(0, bindGroup);
            passEncoder.draw(6);
            passEncoder.end();

            device.queue.submit([commandEncoder.finish()]);
        }

        animationId = requestAnimationFrame(render);
      };

      animationId = requestAnimationFrame(render);
    };

    initWebGPU();

    return () => {
      isMounted = false;
      if (animationId) cancelAnimationFrame(animationId);
    };
  }, []);

  if (error) {
    return (
      <div className="w-full h-full flex items-center justify-center bg-transparent p-8 text-center">
        <div className="max-w-md">
          <p className="text-gray-600 font-mono text-[10px] uppercase tracking-widest">{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full h-full">
      <canvas ref={canvasRef} className="w-full h-full block" />
    </div>
  );
};

export default WebGPUCanvas;

